import{P as e}from"./chunks/PublicUtilityPanel.QYoIU9MT.js";import{o as i,c as o,ag as s,E as r}from"./chunks/framework.DmPmGTlv.js";import"./chunks/theme.BsBmJ8k5.js";const u=JSON.parse('{"title":"Guia do paciente","description":"","frontmatter":{},"headers":[],"relativePath":"guia-do-paciente.md","filePath":"pt/guia-do-paciente.md","lastUpdated":1777060498000}'),c={name:"guia-do-paciente.md"},m=Object.assign(c,{setup(t){return(l,a)=>(i(),o("div",null,[a[0]||(a[0]=s('<h1 id="guia-do-paciente" tabindex="-1">Guia do paciente <a class="header-anchor" href="#guia-do-paciente" aria-label="Permalink to &quot;Guia do paciente&quot;">​</a></h1><blockquote><p>Esta trilha foi pensada para pacientes, familiares, cuidadores e prescritores que precisam de uma visão prática antes de iniciar uma jornada com cannabis medicinal.</p></blockquote><h2 id="antes-da-primeira-consulta" tabindex="-1">Antes da primeira consulta <a class="header-anchor" href="#antes-da-primeira-consulta" aria-label="Permalink to &quot;Antes da primeira consulta&quot;">​</a></h2><div class="docs-grid docs-grid-2"><article class="surface-card"><p class="docs-kicker">Preparação clínica</p><ul class="stack-list"><li>Leve histórico médico e tratamentos anteriores.</li><li>Liste medicamentos em uso, doses e efeitos percebidos.</li><li>Separe exames, laudos e relatórios relevantes.</li><li>Registre objetivos terapêuticos e principais sintomas.</li></ul></article><article class="surface-card"><p class="docs-kicker">Preparação documental</p><ul class="stack-list"><li>Documento com foto.</li><li>Comprovante de endereço atualizado.</li><li>Receita e laudo, quando já disponíveis.</li><li>Documentos do responsável legal, se houver.</li></ul></article></div><h2 id="perguntas-uteis-para-levar-ao-profissional" tabindex="-1">Perguntas úteis para levar ao profissional <a class="header-anchor" href="#perguntas-uteis-para-levar-ao-profissional" aria-label="Permalink to &quot;Perguntas úteis para levar ao profissional&quot;">​</a></h2><div class="surface-card"><ul class="stack-list"><li>Qual é o objetivo terapêutico esperado no meu caso?</li><li>Qual rota faz mais sentido: farmácia, importação ou associação?</li><li>Quais sinais de acompanhamento e segurança devo observar?</li><li>Quais documentos precisam ser atualizados ao longo do tratamento?</li><li>Quando devo retornar para reavaliação clínica?</li></ul></div><h2 id="como-a-abpcm-pode-apoiar" tabindex="-1">Como a ABPCM pode apoiar <a class="header-anchor" href="#como-a-abpcm-pode-apoiar" aria-label="Permalink to &quot;Como a ABPCM pode apoiar&quot;">​</a></h2><div class="docs-grid docs-grid-3"><article class="surface-card"><p class="docs-kicker">Acolhimento</p><h3>Acolhimento inicial</h3><p> A página oficial da ABPCM publica sessão inicial de dúvidas sobre a associação, documentação, funcionamento e políticas do site. </p><p><a href="https://www.abpcm.org.br/service-page/acolhimento-inicial" target="_blank" rel="noreferrer"> Abrir acolhimento inicial </a></p></article><article class="surface-card"><p class="docs-kicker">Suporte complementar</p><h3>Avaliação psicológica</h3><p> A ABPCM também publica página específica de avaliação psicológica como parte de um cuidado mais integrado ao paciente. </p><p><a href="https://www.abpcm.org.br/service-page/avalia%C3%A7%C3%A3o-psicol%C3%B3gica" target="_blank" rel="noreferrer"> Abrir avaliação psicológica </a></p></article><article class="surface-card"><p class="docs-kicker">Rotas especiais</p><h3>Estudo agronômico</h3><p> Para cenários específicos, a associação também publica serviço de estudo agronômico, vinculado a análise técnica de cultivo. </p><p><a href="https://www.abpcm.org.br/service-page/estudo-agron%C3%B4mico" target="_blank" rel="noreferrer"> Abrir estudo agronômico </a></p></article></div><h2 id="boas-praticas-durante-a-jornada" tabindex="-1">Boas práticas durante a jornada <a class="header-anchor" href="#boas-praticas-durante-a-jornada" aria-label="Permalink to &quot;Boas práticas durante a jornada&quot;">​</a></h2><div class="surface-card"><ul class="stack-list"><li>Siga sempre prescrição, dose, forma de uso e retorno definidos pelo profissional responsável.</li><li>Mantenha documentos e comprovantes organizados.</li><li>Reporte efeitos indesejados e mudanças relevantes no quadro clínico.</li><li>Evite decisões baseadas apenas em redes sociais, grupos informais ou promessas comerciais.</li></ul></div><h2 id="proximo-passo" tabindex="-1">Próximo passo <a class="header-anchor" href="#proximo-passo" aria-label="Permalink to &quot;Próximo passo&quot;">​</a></h2><div class="docs-grid docs-grid-2"><article class="surface-card"><p class="docs-kicker">Se você está começando</p><h3>Leia a trilha de acesso</h3><p> A página de [Acesso](/acesso) organiza a decisão entre farmácia, importação excepcional e associação. </p></article><article class="surface-card"><p class="docs-kicker">Se você quer entender o marco regulatório</p><h3>Leia a trilha de legislação</h3><p> A página de [Legislação](/legislacao) concentra Lei 11.343/2006, STJ e Anvisa em uma única visão. </p></article></div><h2 id="utilidades-publicas" tabindex="-1">Utilidades públicas <a class="header-anchor" href="#utilidades-publicas" aria-label="Permalink to &quot;Utilidades públicas&quot;">​</a></h2>',13)),r(e)]))}});export{u as __pageData,m as default};
